import React from "react";
import { useParams } from "react-router-dom";
import "../styles/NewsDetail.css"; // Importing the CSS for the news detail modal

const articles = [
  {
    id: 1,
    title: "LENIENCY IN CRIMINAL SENTENCE FOR JUSTICE COLLABORATORS WHO SUPPORTS LAW ENFORCEMENT AUTHORITIES BY UNCOVERING CRIMINAL CASES",
    date: "06 February, 2025",
    image: "/images/news1.jpg",
    description: "The key to a successful criminal law enforcement depends on the evidence that has been...",
    fullText: "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 2,
    title: "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news2.jpg",
    description: "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText: "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 3,
    title: "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news3.jpg",
    description: "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText: "Full article content goes here. This is the detailed explanation...",
  },
];

const NewsDetail = () => {
  const { id } = useParams();
  const article = articles.find((article) => article.id === parseInt(id));

  return (
    <div className="modal-overlay">
      <div className="modal-content">
        <div className="modal-left">
          <img src={article.image} alt={article.title} />
        </div>
        <div className="modal-right">
          <h3>{article.title}</h3>
          <p className="news-date">📅 {article.date}</p>
          <p className="news-full-text">{article.fullText}</p>
        </div>
      </div>
    </div>
  );
};

export default NewsDetail;
